SELECT COUNT(*) AS total_tests
FROM power_conversion_tests
WHERE device_id = 1;

SELECT MAX(efficiency) AS max_efficiency
FROM power_conversion_tests
WHERE test_date LIKE '2023-04-%';

SELECT test_id, vin, iin, vout, iout, pin, pout, efficiency, test_date, device_id, test_version, load_condition, test_notes, test_location
FROM power_conversion_tests
WHERE efficiency = (SELECT MAX(efficiency) FROM power_conversion_tests);

SELECT test_id, vin, iin, vout, iout, efficiency
FROM power_conversion_tests
ORDER BY test_id, vin, iin, vout, iout, efficiency;

SELECT AVG(T1.efficiency) AS average_efficiency
FROM power_conversion_tests AS T1
WHERE T1.efficiency > 90 AND T1.test_date >= date('now','-30 days');

SELECT MAX(efficiency) AS max_efficiency
FROM power_conversion_tests pct
WHERE test_date BETWEEN '2023-01-01' AND '2023-12-31';

SELECT device_id, COUNT(test_id) AS number_of_tests
FROM power_conversion_tests
GROUP BY device_id;

SELECT test_id, MAX(efficiency) AS peak_efficiency
FROM test_results
GROUP BY test_id;

SELECT d.device_name, p.efficiency
   FROM power_conversion_tests p
   INNER JOIN devices d ON p.device_id = d.device_id;

SELECT test_date, efficiency
FROM power_conversion_tests
ORDER BY test_date DESC;

SELECT AVG(efficiency), test_id
FROM power_conversion_tests
GROUP BY test_id;

SELECT AVG(efficiency) AS average_efficiency
FROM power_conversion_tests
WHERE efficiency < 0.95;

SELECT AVG(efficiency) AS average_efficiency
FROM power_conversion_tests
WHERE device_id = 1;

SELECT test_id, efficiency
FROM power_conversion_tests
WHERE test_id > 0;

SELECT AVG(efficiency) AS average_efficiency
FROM power_conversion_tests
WHERE device_id = 1;

SELECT DISTINCT d.device_name
FROM devices d
JOIN power_conversion_tests pct ON d.device_id = pct.device_id;

SELECT efficiency
FROM test_results
WHERE efficiency > 0.85;
